//! Integration tests for fastmcp dev command

use std::process::{Command, Stdio};
use std::time::Duration;
use tempfile::TempDir;

fn create_test_project() -> TempDir {
    let dir = TempDir::new().unwrap();

    // Create minimal Cargo project
    std::fs::write(dir.path().join("Cargo.toml"), r#"
[package]
name = "test-server"
version = "0.1.0"
edition = "2021"

[dependencies]
fastmcp = { path = "..." }
"#).unwrap();

    std::fs::create_dir(dir.path().join("src")).unwrap();
    std::fs::write(dir.path().join("src/main.rs"), r#"
fn main() {
    println!("Server starting");
    std::thread::sleep(std::time::Duration::from_secs(60));
}
"#).unwrap();

    dir
}

#[tokio::test]
async fn test_dev_starts_server() {
    let project = create_test_project();

    let mut child = Command::new("cargo")
        .args(["run", "--", "dev", project.path().to_str().unwrap()])
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .unwrap();

    // Wait for startup
    tokio::time::sleep(Duration::from_secs(5)).await;

