#[tokio::test]
async fn test_mounted_tools_appear_in_list() {
    let db = ServerBuilder::new("db", "1.0")
        .tool(mock_tool("query"))
        .tool(mock_tool("insert"))
        .build();

    let main = ServerBuilder::new("main", "1.0")
        .tool(mock_tool("health"))
        .mount(db, Some("db"))
        .build();

    let tools = main.list_tools().await.unwrap();
    let names: Vec<_> = tools.tools.iter().map(|t| &t.name).collect();

    assert!(names.contains(&&"health".to_string()));
    assert!(names.contains(&&"db/query".to_string()));
    assert!(names.contains(&&"db/insert".to_string()));
}

#[tokio::test]
async fn test_mounted_tool_can_be_called() {
    let echo = ServerBuilder::new("echo", "1.0")
        .tool(echo_tool())
        .build();

    let main = ServerBuilder::new("main", "1.0")
        .mount(echo, Some("utils"))
        .build();

    let result = main.call_tool("utils/echo", json!({"message": "hello"})).await.unwrap();
    assert!(!result.is_error);
}

#[tokio::test]
async fn test_nested_mounting() {
    let inner = ServerBuilder::new("inner", "1.0")
        .tool(mock_tool("deep"))
        .build();

    let middle = ServerBuilder::new("middle", "1.0")
        .mount(inner, Some("inner"))
        .build();

    let outer = ServerBuilder::new("outer", "1.0")
        .mount(middle, Some("middle"))
        .build();

    // Tool should be at middle/inner/deep
    let tools = outer.list_tools().await.unwrap();
    assert!(tools.tools.iter().any(|t| t.name == "middle/inner/deep"));
}

#[tokio::test]
async fn test_selective_mount_tools_only() {
    let source = ServerBuilder::new("source", "1.0")
        .tool(mock_tool("tool1"))
        .resource(mock_resource("res://data"))
        .prompt(mock_prompt("prompt1"))
        .build();

    let main = ServerBuilder::new("main", "1.0")
        .mount_tools(&source, Some("imported"))
        .build();

    let tools = main.list_tools().await.unwrap();
    let resources = main.list_resources().await.unwrap();
    let prompts = main.list_prompts().await.unwrap();

    assert!(tools.tools.iter().any(|t| t.name == "imported/tool1"));
    assert!(resources.resources.is_empty()); // Not mounted
    assert!(prompts.prompts.is_empty()); // Not mounted
