### Logging/Tracing Requirements

```rust
use tracing::{debug, info, warn, instrument};

impl Router {
    #[instrument(level = "info", skip(self, other))]
    pub fn mount(&mut self, other: &Router, prefix: Option<&str>) -> Result<(), MountError> {
        info!(
            prefix = ?prefix,
            tools = other.tools.len(),
            resources = other.resources.len(),
            prompts = other.prompts.len(),
            "Mounting server components"
        );

        for (name, handler) in &other.tools {
            let new_name = Self::apply_prefix(name, prefix);
            debug!(original = %name, mounted_as = %new_name, "Mounting tool");

            if let Some(existing) = self.tools.get(&new_name) {
                warn!(name = %new_name, "Tool name conflict during mount");
                // Handle based on on_duplicate
            }
            self.tools.insert(new_name, handler.clone());
        }
        // ... similar for resources/prompts
        Ok(())
    }
}
```

Required trace points:
- `INFO`: Mount operation start with component counts
